 1	import * as React from 'react';
 2	import { ActionGroup, Button, ButtonVariant } from '@patternfly/react-core';
 3	import { CheckIcon } from '@patternfly/react-icons/dist/esm/icons/check-icon';
 4	import CloseButton from '../modals/CloseButton';
 5	
 6	export interface ActionGroupWithIconsProps {
 7	  onSubmit: () => void;
 8	  onClose: () => void;
 9	  isDisabled?: boolean;
10	}
11	
12	const ActionGroupWithIcons: React.FC<ActionGroupWithIconsProps> = ({
13	  onSubmit,
14	  onClose,
15	  isDisabled,
16	}) => {
17	  return (
18	    <ActionGroup className="pf-v6-c-form pf-v6-c-form__actions--right">
19	      {onSubmit && (
20	        <Button
21	          type="submit"
22	          onClick={onSubmit}
23	          variant={ButtonVariant.plain}
24	          data-test-id="check-icon"
25	          style={{ padding: '0' }}
26	          isDisabled={isDisabled}
27	        >
28	          <CheckIcon />
29	        </Button>
30	      )}
31	      <CloseButton
32	        additionalClassName="co-close-button--no-padding"
33	        dataTestID="close-icon"
34	        onClick={onClose}
35	      />
36	    </ActionGroup>
37	  );
38	};
39	
40	export default ActionGroupWithIcons;

